-- Addon namespace
local _, Private = ...
local L = Private.Libs.ACL

-- Lua functions
local tinsert = table.insert

-- Global environment
local _G = _G

-- Plater profile
function Private:Setup_Plater(installer)
	if not Private.IsAddOnLoaded('Plater') then Private:Print('Plater ' .. L["is not installed or enabled."]) return end

	if Private.ElvUI then
		-- Make sure the ElvUI module is off when using Plater
		ElvUI[1].private.nameplates.enable = false
	end

	-- Global db
	local dev = Private.Addon.db.global.dev

	-- Profile name
	local name = (dev and 'Luckyone') or 'Luckyone ' .. Private.Version

	-- Profile string
	local profileString = '!PLATER:2!'

	local data = _G.Plater.DecompressData(profileString, 'print')

	-- Profile import
	if PlaterDB.profiles[name] then -- Profile already exists, don't import, just load
		tinsert(PlaterDB.profileKeys, Private.myNameRealm)
		PlaterDB.profileKeys[Private.myNameRealm] = name
	else -- Import the profile string
		PlaterDB.profiles[name] = data
		PlaterDB.profileKeys[Private.myNameRealm] = name
	end

	if installer then
		_G.LuckyoneInstallStepComplete:ShowMessage(L["Plater profile has been set."])
	end

	Private:Print(L["Plater profile has been set."])
end
